<template>
<div>
    <div class="v-popup-wrapper" ref="popup-wrapper">
    
 <div class="v-popup  col-4 col-xl-4 col-lg-4 col-md-4">
    
            <div class="v-popup-header">
            <!-- <span>Popup name</span> -->
            <!-- <span
            @click="closePopup"
            >
                cancle
                </span> -->
        </div>
        <div class="v-popup-content">
            <slot></slot>
        </div>
        <div class="v-popup-footer"></div>
     
     
    </div>
</div>
</div>

   
</template>

<script>
export default {
    name: "v-popup",
    props: {},
    data(){
        return{}
    },
    methods:{
        closePopup(){
            this.$emit('closePopup')
        }
    },
    mounted() {
        let vm = this;
        document.addEventListener('click', function(item){
            if(item.target === vm.$refs['popup-wrapper']) {
                vm.closePopup()
            }
        })
    },
}
</script>

<style >


.v-popup-wrapper{
    /* background-color: rgba(0, 0, 0, 0.3);
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    right: 0;
    left: 0;
    top: 0;
    bottom: 0;
    z-index: 1; */
    position: fixed;
    z-index: 99999;
    top: 0; left: 0; right: 0; bottom: 0;
    display: flex;
    align-items: center;
    justify-content: flex-end;
    overflow-y: auto;
    background-color: rgba(0, 0, 0, .3);
 
   

}
.v-popup{
     padding: 16px;
    width: 440px;
    height: 545px;
    /* position: fixed; */
    background: #fff;
    -webkit-box-shadow: 0 0 0 17px 0 #e7e7e7e7;
    box-shadow: 0 0 0 17px 0 #e7e7e7e7;
    z-index: 10;
    position: absolute;
    margin-right: 14%;
}

@media only screen and (max-width: 1869px){ 
    .v-popup{
        
    margin-right: 8%;
    }
 }

 @media only screen and (max-width: 1600px){ 
    .v-popup{
        
    margin-right: 6%;
    }
 }


@media only screen and (max-width: 1440px){ 
    .v-popup{
        
    margin-right: 4%;
    }
 }

 /* @media only screen and (max-width: 1800px){ 
    .v-popup{
        
    margin-right: 12%;
    }
 } */




/* .v-popup-wrapper{
    background-color: rgba(0, 0, 0, 0.3);
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    width: 100%;
    height: 100%;
    z-index: 1;
}
.v-popup{
    padding: 16px;
    width: 440px;
    height: 545px;
    position: fixed;
    background: #fff;
    box-shadow: 0 0 0 17px 0 #e7e7e7e7;
    border:solid;
    margin-left: 460px;
    z-index: 10;
} */
 
</style>




