
<template >

  <div>
      <transition name="bounce" >
    <v-popup 
            v-if="isInfoPopupVisible"
            @closePopup="closeInfoPopup"
            >
            <div>
                <p class="popup-header">{{$t('reg')}}</p>
            </div>
            <div class="col-7">
                <form class="form-login">
                    <label class="form-text" for="username">{{$t('phoneNum')}}:</label>
                    <input class="input-log-in" type="tel" id="username" name="username" value="+380">
                    <label class="form-text" for="pwd">Пароль:</label>
                    <img id="eye" src="static/img/eye.png" alt="eye" >
                    <input class="input-log-in-1" type="password" id="pwd" name="pwd" > 
                      
                    <button class="form-text btn-log-in" type="submit">{{$t('regBtn')}}</button>
                   
                </form>
                
            </div>
            
              <div class="col">
                <p class="form-text-or">{{$t('or')}}</p>
              
            
            
                <p class="form-text popup-header">{{$t('logInHelp')}}</p>
                <div class="icons-wrapper">
                         <div class="log-in-icons">
                    <i class="fa fa-facebook" aria-hidden="true"></i>
                </div>
                 <div class="log-in-icons">
                    <i class="fa fa-google" aria-hidden="true"></i>
                </div>
                </div>
           
               
         
              </div>
      
            
    </v-popup>
    </transition>
          <header>
            <nav id="nav">
               
                <div class="container-header">
                    
                    <div class="row">
                        <div class="col">
                            <ul class="navbar-nav">
                                <div class="dd ">
                                <button id="drop-down" @click="isOpenA = ! isOpenA" >
                                    <img class="logo-category" src="static/img/menu.jpg" alt="enu" />
                                </button>
                                
                       
       
                                <button id="drop-down-word" @click="isOpenA = ! isOpenA" >
                                     {{$t('choseCat')}}
                                </button>
                            </div>
                        <transition name="fade" >
                        <ul class="drop-list" v-show="isOpenA" >
                            <li class="drop-item">Спорт<i class="fa fa-angle-right"></i></li>
                            <li class="drop-item">Поліграфія<i class="fa fa-angle-right"></i></li>
                            <li class="drop-item">Майстри та майстрині<i class="fa fa-angle-right"></i></li>
                             <li class="drop-item">Розваги<i class="fa fa-angle-right"></i></li>
                        </ul>
                         </transition>
                    
           
                  
            <li class="nav-link link lang"> 
                
                <div class="normal-container">
	
			        <form class="submit-rating">
				        <input id="meh"  name="satisfaction" type="radio" /> 
				        <input id="fun" name="satisfaction" type="radio" /> 
                        <label for="fun" @click="setLocale('ru')"  class="rating-label rating-label-fun">Ру</label>
				        <label for="fun"   class="rating-label rating-label-fun rating-label-meh">|</label>
				        <label for="meh" @click="setLocale('en')" class="rating-label rating-label-meh">Укр</label>
			        </form>
                </div>   
             </li>
        </ul>
    </div>
                    <div class="col">
                        <div class="logo">
                            <img src="static/img/logo.jpg" alt="logo" />
                        </div>
                    </div>
                    <div class="col">
                        <ul class="navbar-nav-right">
                           
                            <li class="nav-link">
                                <form class="form-search">
                                    <i class="fa fa-search" aria-hidden="true"></i>
                                    <input class="input-search"  type="search"  aria-label="Search"  />
                                </form>
                               
                            </li>
                            <li>
                                <div class="log-in">
                                <button class="log-in-popup-btn" @click="showPopupInfo">
                                        <img class="user" src="static/img/user.png" alt="log-in" >
                                         <p class="entrance" href="#">{{$t('logIn')}}</p>
                                </button>
                                    </div>
                                </li>
                            </ul>
                        </div>
                    </div>
                    <div class="line"></div>
                </div>
            </nav>
            <div class="container-app">
                <div class="banner">
                
                <div class="row">
                    <div class="col-xl-12">
                         <img class="card-img-top"   src="static/img/Banner.png" alt="Banner" />
                    </div>
                    
                </div>
               
            </div>
 
      
   

            </div>
            
        </header>
   
  </div>
</template>

<script>
import vPopup from '../popup/v-popup'
let body = document.querySelector('body');
export default {
    
  name: 'Nav',
  components:{
      vPopup
  },
     data () {
    return {
     isOpenA: false,
     isInfoPopupVisible: false,
    
     
    
    }
  },
    methods: {
     showPopupInfo(){
         this.isInfoPopupVisible = true;
         body.classList.add('lock');
     },
     closeInfoPopup(){
         this.isInfoPopupVisible = false;
        body.classList.remove('lock');
     },
     setLocale(locale){
         this.$i18n.locale = locale
     },
  
  
     
    },


 
    
}

</script>

<style scoped>

.fade-enter-active, .fade-leave-active {
  transition: opacity .3s;
}
.fade-enter, .fade-leave-to /* .fade-leave-active до версии 2.1.8 */ {
  opacity: 0;
}
  .bounce-enter-active {
  animation: bounceIn .3s;
  }
  .bounce-leave-active {
  animation: bounceIn .3s reverse;
  }

  @keyframes bounceIn {
  0% {
    transform: scale(0.1);
    opacity: 0;
  }
  60% {
    transform: scale(1.2);
    opacity: 1;
  }
  100% {
    transform: scale(1);
  }
  }

.lock{
  overflow: hidden;
}

.line{
    width: 1362px;
    border-bottom: solid 1px rgba(0, 0, 0, 0.37);
    position: absolute;
    margin-top: 60px;
    margin-left: 30px;
}

.popup-header{
    font-size: 40px;
    margin-bottom: 50px;
    text-align: center;
    margin-top: 30px;
}
.form-text{
    font-size: 14px;
    margin-bottom: 10px;
}
.input-log-in {
    border: none;
    outline: none;
    border-bottom: 1px solid rgba(0, 0, 0, 0.35);
    width: 320px;
    margin-bottom: 25px;
}
.btn-log-in{
    margin-top: 25px;
    border: none;
    outline: none;
    background: #DDDBDB;
    width: 196px;
    height: 50px;
    margin-left: 60px;
        font-family: 'Raleway', sans-serif;
    font-style: normal;
    font-weight: 300;
    font-size: 18px;
    line-height: 21px;
    color: #000;
}
.form-login{
    margin-left: 30px;
}


.form-text-or {
  overflow: hidden;
  position: relative;
  margin: 0;
  text-align: center;
  white-space: nowrap;
  margin-right: 40px;
    margin-left: 40px;
    margin-top: 38px;
}
.form-text-or:before,
.form-text-or:after {
  content: '';
  display: inline-block;
  position: relative;
  top: -1px;
  width: 50%;
  height: 1px;
  vertical-align: middle;
  background: black;
}
.form-text-or:before {
  left: -10px;
  margin-left: -50%;
}
.form-text-or:after {
  left: 10px;
  margin-right: -50%;
}

.log-in-icons{
    margin-top: 7px;
    text-align: center;
    height: 45px;
    width: 45px;
    border: 1px solid #DDDBDB;
    font-size: 20px;
    display: inline-block;
    margin-left: 15px;
    margin-right: 15px;
    padding-top: 10px;
}

.icons-wrapper{
    text-align: center;
}

.input-log-in-1{
    border: none;
    outline: none;
    border-bottom: 1px solid rgba(0, 0, 0, 0.35);
    width: 320px;
    margin-bottom: 25px;
}
#eye {
    height: 20px;
    width: 24px;
    display: inline-block;
    position: absolute;
    margin-top: 17px;
    
    margin-left: 235px;
}

.log-in-popup-btn{
  background: none;
  border: none;
  outline: none;
  cursor: pointer;
}
.log-in{
 margin-left: 75px;   
}

.dd{
    cursor: pointer;
    
}
.navbar-nav, #drop-down, #drop-down-word{
    cursor: pointer;
}



.ru, .ukr {
    color: rgba(0, 0, 0, 0.5);
}

/* #ukr{
    color: #000;
} */

/* .lang{
    color: rgba(0, 0, 0, 0.5);
} */
.button {
  -webkit-appearance: none;
  appearance: none;
  border: 0;
  /* background: gray; */
  height: 50px;
  width: 50px;
  margin: 10px;
  outline: none;
  display: inline-block;
  border-radius: 50%;
  color: gray ;
  
}

.button:checked {
  background: black;
  color: #000;
}


.normal-container {
	 position: absolute;
	 height: 100%;
	 width: 80%;
}
 /* .smile-rating-container {
	 position: relative;
	 height: 10%;
	 min-width: 220px;
	 max-width: 520px;
	 margin: auto;
	 
	 top: 20%;
} */
 /* .submit-rating {
	 display: flex;
	 align-items: center;
	 justify-content: center;
} */
 .rating-label {

	 cursor: pointer;
	 color: #d0cccd;
	
}
 .rating-label:hover, .rating-label:active {
	 color: #d0cccd;
}
 .rating-label-fun {
	 /* left: -58px; */
	 text-align: right;
}
 .rating-label-meh {
	 left: 58px;
	 text-align: left;
	 color: #222;
}
 /* .smile-rating-container input {
	 display: none;
} */
.submit-rating input {
     display: none;
}
 /* .toggle-rating-pill {
	 position: relative;
	 height: 65px;
	 width: 165px;
	 background: #d0cccd;
	 border-radius: 500px;
	 transition: all 500ms;
} */
 /* .smile-rating-toggle {
	 position: absolute;
	 width: 54px;
	 height: 54px;
	 background-color: white;
	 left: 182px;
	 border-radius: 500px;
	 transition: all 500ms;
	 z-index: 4;
} */
 /* .rating-eye {
	 position: absolute;
	 height: 12px;
	 width: 8px;
	 top: 22px;
	 background: #d0cccd;
	 border-radius: 500px;
	 z-index: 5;
	 transition: all 440ms;
	 animation: blink-eye 3s infinite;
} */
 



/* Toggle Changes */
 #meh:checked ~ .rating-label-meh {
	 color: #555e63;
}
 #fun:checked ~ .rating-label-meh {
	 color: #d0cccd;
}
 #fun:checked ~ .mouth {
	 border: 4px solid #00b9ee;
	 border-bottom-color: rgba(1, 1, 1, 0);
	 border-right-color: rgba(1, 1, 1, 0);
	 border-left-color: rgba(1, 1, 1, 0);
	 top: 23px;
	 left: 291px;
	 transform: rotateX(180deg);
	 border-radius: 100%;
}
 #fun:checked ~ .rating-label-fun {
	 color: #555e63;
}
 /* #fun:checked ~ .smile-rating-toggle {
	 left: 282px;
} */
 /* #fun:checked ~ .rating-eye-left {
	 left: 292px;
} */
 #fun:checked ~ .rating-eye-right {
	 left: 316px;
}
 #fun:checked ~ .toggle-rating-pill {
	 background-color: #00b9ee;
}
 #fun:checked ~ .rating-eye {
	 background-color: #00b9ee;
}


/* @media only screen and (max-width: 1440px){ 
    .banner {
    width: 1320px;
    height: 500px;
    margin: auto;
    margin-top: 30px;
    margin-right: 70px;
}
 } */

 @media only screen and (max-width: 524px) {
	/* Toggle Changes */
	 .normal-container {
		 position: absolute;
		 height: 100%;
		 width: 100%;
	}
	 /* .smile-rating-container {
		 position: relative;
		 height: 10%;
		 width: 490px;
		 margin: auto;
		 font-family: 'Roboto', sans-serif;
		 top: 20%;
	} */
	 /* .submit-rating {
		 display: flex;
		 align-items: center;
		 justify-content: center;
	} */
	 .rating-label {
		 position: relative;
		 font-size: 1.6em;
		 text-align: center;
		 flex: 0.34;
		 z-index: 3;
		 font-weight: bold;
		 cursor: pointer;
		 color: #d0cccd;
		 transition: 500ms;
	}
	 .rating-label:hover, .rating-label:active {
		 color: #d0cccd;
	}
	 .rating-label-fun {
		 left: -58px;
		 text-align: right;
	}
	 .rating-label-meh {
		 left: 50px;
		 text-align: left;
		 color: #222;
	}
	 .smile-rating-container input {
		 display: none;
	}
	 /* .toggle-rating-pill {
		 position: relative;
		 height: 65px;
		 width: 165px;
		 background: #d0cccd;
		 border-radius: 500px;
		 transition: all 500ms;
	} */
	 /* .smile-rating-toggle {
		 position: absolute;
		 width: 54px;
		 height: 54px;
		 background-color: white;
		 left: 168px;
		 border-radius: 500px;
		 transition: all 500ms;
		 z-index: 4;
	} */
	 .rating-eye {
		 position: absolute;
		 height: 12px;
		 width: 8px;
		 background: #d0cccd;
		 border-radius: 500px;
		 top: 22px;
		 z-index: 5;
		 transition: all 440ms;
	}
	 .rating-eye-left {
		 left: 180px;
	}
	 .rating-eye-right {
		 left: 201px;
	}
	 .mouth {
		 position: absolute;
		 width: 28px;
		 height: 20px;
		 z-index: 6;
		 border: 4px solid #d0cccd;
		 border-radius: 10%;
		 border-bottom-color: rgba(1, 1, 1, 0);
		 border-right-color: rgba(1, 1, 1, 0);
		 border-left-color: rgba(1, 1, 1, 0);
		 top: 42px;
		 left: 177px;
		 transition: all 500ms;
	}
	 #meh:checked ~ .rating-label-meh {
		 color: #555e63;
	}
	 #fun:checked ~ .rating-label-meh {
		 color: #d0cccd;
	}
	 #fun:checked ~ .mouth {
		 border: 4px solid #00b9ee;
		 border-bottom-color: rgba(1, 1, 1, 0);
		 border-right-color: rgba(1, 1, 1, 0);
		 border-left-color: rgba(1, 1, 1, 0);
		 top: 23px;
		 left: 275px;
		 transform: rotateX(180deg);
		 border-radius: 100%;
	}
	 #fun:checked ~ .rating-label-fun {
		 color: #555e63;
	}
	 /* #fun:checked ~ .smile-rating-toggle {
		 left: 266px;
	} */
	 #fun:checked ~ .rating-eye-left {
		 left: 275px;
	}
	 #fun:checked ~ .rating-eye-right {
		 left: 300px;
	}
	 #fun:checked ~ .toggle-rating-pill {
		 background-color: #00b9ee;
	}
	 #fun:checked ~ .rating-eye {
		 background-color: #00b9ee;
	}
}
 



</style>




  
  



